// Нормализуем входные данные и конвертируем Markdown → Telegram HTML
// Telegram parse_mode=HTML поддерживает: <b>, <i>, <u>, <s>, <code>, <pre>, <a>, <tg-spoiler>
// Используем placeholder-систему: сначала изолируем кодовые блоки, затем форматируем
// обычный текст, затем восстанавливаем код — чтобы форматирование не ломалось внутри кода.

const input = $input.first().json
let text = String(input.replyText || input.text || input.fallbackText || '')
const chatId = input.chatId || ''

// 1. Сохраняем кодовые блоки во временный массив, заменяем placeholder'ами
const codeBlocks = []

// Многострочные блоки: ```code``` → \x00CODE{N}\x00
text = text.replace(/```(?:\w+\n)?([\s\S]*?)```/g, (_, code) => {
  const idx = codeBlocks.length
  codeBlocks.push('<pre>' + code.trim() + '</pre>')
  return `\x00CODE${idx}\x00`
})

// Инлайн-код: `code` → \x00CODE{N}\x00
text = text.replace(/`([^`]+)`/g, (_, code) => {
  const idx = codeBlocks.length
  codeBlocks.push('<code>' + code + '</code>')
  return `\x00CODE${idx}\x00`
})

// 2. Форматируем обычный текст (placeholder'ы не задеты — в них нет спецсимволов)
text = text
  // **bold** → <b>bold</b>
  .replace(/\*\*(.+?)\*\*/g, '<b>$1</b>')
  // *italic* → <i>italic</i> (не матчит **, * item, или * внутри кода)
  .replace(/(?<!\*)\*(?!\s)([^*]+?)(?<!\s)\*(?!\*)/g, '<i>$1</i>')
  // __underline__ → <u>underline</u>
  .replace(/__(.+?)__/g, '<u>$1</u>')
  // ~~strikethrough~~ → <s>strikethrough</s>
  .replace(/~~(.+?)~~/g, '<s>$1</s>')
  // [text](url) → <a href="url">text</a>
  .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>')

// 3. Восстанавливаем кодовые блоки из placeholder'ов
text = text.replace(/\x00CODE(\d+)\x00/g, (_, idx) => codeBlocks[parseInt(idx)] || '')

return [{ json: { text, chatId } }]

// Готовим текст для AI-очистки перед озвучиванием
// Telegram API ответ может быть вложенным (result.text) или плоским (text)
const data = $input.first().json
const text = String(
  data.text || (data.result || {}).text || $('Нормализуем входные данные').first().json.text || ''
)

return {
  json: {
    systemPrompt: `Ты — ассистент, который озвучивает результат работы кодинг-агента OpenCode через TTS-синтезатор. Твоя задача — взять ответ OpenCode и ПОНЯТНО ОБЪЯСНИТЬ пользователю, что было сделано, изменено или предложено. Адаптируй текст для голосового воспроизведения (TTS). ПРАВИЛА: 1. Сохрани СМЫСЛ и все важные детали — пользователь должен понять результат. 2. Переведи английский на русский, если есть. 3. Убери markdown, бэктики, пути к файлам, URL, куски кода, массивы, JSON, логи, технический мусор. 4. Используй естественные, удобные для произношения формулировки. Избегай сложносоставных слов, труднопроизносимых конструкций, неестественного порядка слов. 5. Пиши так, как нормальный человек говорит — короткими, ритмичными предложениями, без канцелярита. 6. НЕ упрощай до примитива — сохраняй интеллектуальный тон, как коллега объясняет коллеге. 7. Не добавляй вводных фраз вроде 'OpenCode вернул', 'Агент сообщает', 'Согласно результату'. Сразу к сути. 8. Plain text, без форматирования. Не более 5 предложений.`,
    userPrompt: text,
  },
}

// Извлекаем очищенный текст из ответа AI
const toText = (v) => String(v ?? '').trim()

let cleanText = ''
try {
  cleanText = toText($('AI очистка текста').first().json.output ?? $('AI очистка текста').first().json.text ?? '')
} catch (_) {}

// Fallback: AI не ответил или ошибка — используем текст из входа
if (!cleanText) {
  const input = $input.first().json
  cleanText = toText(input.text || (input.result || {}).text || '')
}

// Если всё ещё пусто — последний рубеж: текст из нормализации (содержит fallbackText)
if (!cleanText) {
  try {
    cleanText = toText($('Нормализуем входные данные').first().json.text)
  } catch (_) {}
}

// Финальная очистка
cleanText = cleanText
  .replace(/```[\s\S]*?```/g, '')
  .replace(/`([^`]*)`/g, '$1')
  .replace(/[*_~]{1,2}/g, '')
  .replace(/\[([^\]]*)\]\([^)]*\)/g, '$1')
  .replace(/\s+/g, ' ')
  .trim()

return { json: { cleanText } }
